from flask import Flask, request, jsonify

app = Flask(__name__)

@app.route('/submit_data', methods=['POST'])
def submit_data():
    if request.is_json:
        data = request.json
        return jsonify({"message": "JSON veri başarıyla alındı!", "data_received": data}), 200
    else:
        # Form-urlencoded veya multipart/form-data için
        data = request.form.to_dict()
        return jsonify({"message": "Form verisi başarıyla alındı!", "data_received": data}), 200

if __name__ == '__main__':
    app.run(debug=True)
